#include <vector>
#include <algorithm>
#include <numeric>
#include <cmath>
#include <unordered_set>

using namespace std;

long long solve(std::vector<long long> nums) {
    double sum = accumulate(nums.begin(), nums.end(), 0.0);
    double average = sum / nums.size();

    unordered_set<long long> numSet(nums.begin(), nums.end());

    long long candidate = ceil(average) + 1;
    if (average >= floor(average)) {
        candidate = floor(average) + 1;
    }

    // Ensure candidate is at least 1
    candidate = max(candidate, 1LL);

    while (true) {
        if (numSet.find(candidate) == numSet.end() && candidate > average) {
            return candidate;
        }
        candidate++;
    }
}
